#!/usr/bin/env python3
import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    out = []
    for i in range(0, len(data), 4):
        if i + 3 >= len(data):
            break
        a, b, x, y = data[i], data[i+1], data[i+2], data[i+3]
        messi = 2 * a + b
        ronaldo = 2 * x + y
        if messi > ronaldo:
            out.append("Messi")
        elif ronaldo > messi:
            out.append("Ronaldo")
        else:
            out.append("Equal")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

